root.js-content:
stp.writeLog("Start: Received Baseline Report");
stp.setAutoProcess(true);
stp.setUserId("CSBANK");

var sRptId = stp.getXslMsgTagVal("message/Document/BaselnRpt/RptId","Id");
stp.writeLog("sRptId========="+sRptId);
var sIndex = sRptId.indexOf("-");
var sBIC = sRptId.substr(0,sIndex);
stp.writeLog("sBIC========="+sBIC);
var sBuyrBkBIC = stp.getXslMsgTagVal("message/Document/BaselnRpt/BuyrBk","BIC");
var sSellrBkBIC = stp.getXslMsgTagVal("message/Document/BaselnRpt/SellrBk","BIC");
var sBuyrNm = stp.getXslMsgTagVal("message/Document/BaselnRpt/Buyr","Nm");
var sSellrNm = stp.getXslMsgTagVal("message/Document/BaselnRpt/Sellr","Nm");
var sUnitNm = "";
if(sBIC == sBuyrBkBIC){
  sUnitNm = sBuyrNm;
  stp.updateFieldValue("TSU_TRX_ROLE","BUYER");
}else{
  sUnitNm = sSellrNm;
  stp.updateFieldValue("TSU_TRX_ROLE","SELLER");
}
var arrKeys = [["C_UNIT_NAME",sUnitNm]];
var arrGetDataResult = stp.SYS_getCUBKVal("GetUnitCodeByNm",arrKeys);
var sUnitCode = arrGetDataResult[0];
stp.writeLog("sUnitCode========="+sUnitCode);
stp.setCmpId(sUnitCode);

var sTxId = stp.getXslMsgTagVal("message/Document/BaselnRpt/TxId","Id");
stp.writeLog("sTxId========="+sTxId);
var arrKeys1 = [["TSU_TID",sTxId]];
var arrGetDataResult1 = stp.SYS_getCUBKVal("GetMainRefByTxId",arrKeys1);
var sMainRef = arrGetDataResult1[0];
//var sMainRef = stp.getSimpleRef(17);
stp.setMainRef(sMainRef);
stp.writeLog("sMainRef****"+sMainRef);
stp.updateFieldValue("PARENT_MAIN_REF",sTxId);
stp.updateFieldValue("CURRNT_STATUS","Received Baseline Report");
stp.writeLog("End: Received Baseline Report");
